function LNativeHelper.CopyToClipboard(msg)
    if not msg then return false end
    msg  = tostring(msg)
    if string.isempty(msg) then return false end
    if CS.IsWebGL() then
        LNativeHelper.CallMethod("CopyToClipboard", msg)
        return true
    end
    if CS.CopyStrToSystemClipboard(msg) then
        return true
    end
    return false
end
