function LNativeHelper.CheckPermissionForObserverScreenShot()
    if CS.IsOSAndroid() then
        local apiLv = LNativeHelper.GetCurrentApiVersion()
        if apiLv < 23 then
            return true
        elseif apiLv < 33 then
            --android 13+ 开始图片文件开始细化权限
            local permission = "android.permission.READ_EXTERNAL_STORAGE"
            if not LNativeHelper.CheckPermission(permission) then
                return false
            end
        else
            --android 13+ 开始图片文件开始细化权限
            local permission = "android.permission.READ_MEDIA_IMAGES"
            if not LNativeHelper.CheckPermission(permission) then
                return false
            end
        end
        return true
    end
    return true
end

function LNativeHelper.RequestPermissionForObserverScreenShot(message, okStr, cancelStr)
    if CS.IsOSAndroid() then
        local apiLv = LNativeHelper.GetCurrentApiVersion()
        if apiLv >= 23 and apiLv <= 32 then
            --android 13+ 开始图片文件开始细化权限, READ_EXTERNAL_STORAGE 弃用
            local permission = "android.permission.READ_EXTERNAL_STORAGE"
            LNativeHelper.CallMethod(LNativeMethod.DoRequestPermission, message, okStr, cancelStr, permission)
        elseif apiLv >= 33 then
            --android 13+ 开始图片文件开始细化权限
            local permission = "android.permission.READ_MEDIA_IMAGES"
            LNativeHelper.CallMethod(LNativeMethod.DoRequestPermission, message, okStr, cancelStr, permission)
        end
        return true
    end
end

function LNativeHelper.CheckPermissionForMedia()
    if CS.IsOSAndroid() then
        local apiLv = LNativeHelper.GetCurrentApiVersion()
        if apiLv < 23 then
            return true
        elseif apiLv < 29 then
            --android 10 以下(api level 28 以及以下， 使用MediaStore写入媒体库有bug， 直接写入图片到相册目录， 需要写权限)
            --android 10 开始(可以使用 MediaStore写入图片到媒体库，该功能不需要权限)
            local permission = "android.permission.WRITE_EXTERNAL_STORAGE"
            if not LNativeHelper.CheckPermission(permission) then
                return false
            end
        end
        return true
    end
    return true
end

function LNativeHelper.RequestPermissionForMedia(message, okStr, cancelStr)
    if CS.IsOSAndroid() then
        local apiLv = LNativeHelper.GetCurrentApiVersion()
        if apiLv >= 23 and apiLv < 29 then
            --android 10 以下(api level 28 以及以下， 使用MediaStore写入媒体库有bug， 直接写入图片到相册目录， 需要写权限)
            --android 10 开始(可以使用 MediaStore写入图片到媒体库，该功能不需要权限)
            local permission = "android.permission.WRITE_EXTERNAL_STORAGE"
            LNativeHelper.CallMethod(LNativeMethod.DoRequestPermission, message, okStr, cancelStr, permission)
        end
        return true
    end
end

function LNativeHelper.CheckPermission(permission)
    if string.isempty(permission) then return false end
    return NativeHelper.CheckPermission(permission)
end

function LNativeHelper.OpenAppStore(url,packageName,storeName)
    if CS.IsOSIos() then
        local link = string.gsub(url,'https://',"itms-apps://")
        CS.UApplication.OpenURL(link)
    elseif CS.IsOSAndroid() then
        if not string.isempty(url) then
            CS.UApplication.OpenURL(url)
        else
            NativeHelper.OpenAppStore(packageName,storeName)
        end
    else
        if not string.isempty(url) then
            CS.UApplication.OpenURL(url)
        end
    end
end

