---@endregion native call

local _splitToken = "{#t#}"
local _splitEmpty = "{null}"
function LNativeHelper.Encode(methodName, ...)
    local args = {...}
    if #args == 0 then
        return methodName
    end
    local datas = {methodName.._splitToken}
    for k,v in ipairs(args) do
        local arg = tostring(v)
        local newArg = string.gsub(arg, _splitToken,"")
        if(newArg ~= arg) then
            LogError("invalid string in sdk args")
        end
        if string.isempty(newArg) then
            newArg = _splitEmpty
        end
        table.insert(datas, newArg.._splitToken)
    end
    local str = table.concat(datas, "")
    return str
end

function LNativeHelper.Decode(msg)
    local arr = string.split(msg, _splitToken)
    if not arr or #arr == 0 then return end
    local methodname = arr[1]
    local args = nil
    if #arr > 1 then
        table.remove(arr, 1)
        args = arr
    else
        args = {}
    end
    return methodname, args
end

return LNativeHelper